import { Mat4, Quat, Rect, size, Size, UITransform, v2, v3, Vec2, Vec3 } from 'cc';
import { ecsclass } from '../../core/EcsManager';
import { IEntity } from '../../core/EcsObject';
import { EcsComponent } from '../../ecs/EcsComponent';

